  "intent_description": "Source 192.168.0.12 cannot reach destination 172.16.0.12 because R2 has no return route for 192.168.0.0/24; after remediation replies from 172.16.0.12 should route back to 192.168.0.12 and pings should succeed.",
  "target": "router2",
  "needs_fix": true,
  "plan": {
    "problem": "Router2 has no route for 192.168.0.0/24, so return traffic from 172.16.0.12 is unroutable.",
    "fix_summary": "Add a static route on router2 for 192.168.0.0/24 via next-hop 10.0.0.1 (assumed R1). Previous add_static_route failed because next_hop was incorrectly set to 10.0.0.2 (R2's own address).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "network=192.168.0.0",
          "mask=255.255.255.0",
          "next_hop=10.0.0.1"
        ]
      }
    ]
  }
}

